function merge(a: number[], b: number[]): number[] {
  const result: number[] = []
  let i = 0, j = 0
  while (i < a.length && j < b.length) {
    if (a[i] <= b[j]) { result.push(a[i]); i++ }
    else { result.push(b[j]); j++ }
  }
  while (i < a.length) { result.push(a[i]); i++ }
  while (j < b.length) { result.push(b[j]); j++ }
  return result
}

