function minPathSum(grid: number[][]): number {
  const memo: Map<string, number> = new Map()
  function dp(r: number, c: number): number {
    if (r === grid.length - 1 && c === grid[0].length - 1) return grid[r][c]
    const key = `${r},${c}`
    if (memo.has(key)) return memo.get(key)!
    let best = Infinity
    if (r + 1 < grid.length) best = Math.min(best, dp(r + ___, c))
    if (c + 1 < grid[0].length) best = Math.min(best, dp(r, c + ___))
    const result = grid[r][c] + best
    memo.set(key, result)
    return result
  }
  return dp(0, 0)
}

const grid: number[][] = [
  [1, 3, 1],
  [1, 5, 1],
  [4, 2, 1]
]
console.log(minPathSum(grid))
